(window.webpackJsonp=window.webpackJsonp||[]).push([[29],{637:function(t,e,n){"use strict";n.r(e);var o=n(16),l=Object(o.a)({},(function(){var t=this,e=t.$createElement,n=t._self._c||e;return n("ContentSlotsDistributor",{attrs:{"slot-key":t.$parent.slotKey}},[n("blockquote",[n("p",[t._v("This is official blog theme.\n"),t._v("\n2020年的最后一天，我梦见自己死了，这场梦很真实，以至于我没有意识到我是在做梦，我很庆幸我还活着。")])]),t._v(" "),n("p",[t._v("梦的开始是我和姐姐坐车回村子的路上，司机说到，这条路有很多孤魂野鬼，如果你是一个人走就会被鬼夺走身体。于是我谈起了一年前放假回家走这条路的经历，现在看来确实有很多奇怪的地方，我记得当时走这条路，走到后半段时越来越感觉不到意识，也忘记了我为什么走这条路，但好在我加快脚步走回家了。说罢司机告诉我们前面碰到一路人，他们也是开车回村子，不知为什么其中几个人上了我们的车，然后我们掉头回镇上了。返回的路上，司机开的很不稳，忽然车子从天桥上翻了下来，我急忙动用意念，车子才重新平稳的行驶起来。车子到了终点又踏上回村子的道路。")]),t._v(" "),n("p",[t._v("就在这时，前面响起了枪声，车内的人中了枪，车后也出现一群人不断的朝向车后开枪，我吓得赶忙趴到座位上，祈祷着我们平安甩开这波人。车子又开了一段路 ，我们碰见一队身穿迷彩的特警和这伙人交火，双方伤亡惨重，我们也把最后的希望寄托在这些特警身上，眼看着特警们逐渐劣势，我们也抓紧驶进回村子的那条路上，但那伙人仍然穷追不舍。在车上，我和姐姐很担心把他们引到村子会带来灾难，于是像打电话告诉村里人提前躲起来，但是手机都没有信号。车子也在受击中开不动了，于是我们急忙下车跑回了村子。")]),t._v(" "),n("p",[t._v("一进村子我就找了一户人家躲了进去，我躲在了鸡窝旁边，用箱子把自己挡了起来，让那伙人以为我躲进了鸡窝里面，借此逃过一劫。正当我以为安全了的时候，发现身后的栅栏有一双脚，是谁在这里上厕所，我小心翼翼的抬头和他对视了起来，好在他是我们村民，不是追杀我们的人，我请求他不要泄露我的位置，他同意了。突然我察觉到不对，他为什么没有躲起来，而没有被杀掉呢？那只有一个原因，就是他已经投降叛变了！我立马起身想逃离这个地方，也看到他在向追杀我们的人报告我的位置，但我跑的再快也不会有子弹快，我察觉到自己中了枪，眼前一黑我就失去了意识。我知道我已经死了，可我还有好多要做事情没有做，我很遗憾。学了这么多年的编程，最后却没有一个自己的作品，也没有了实现作品的机会了。")]),t._v(" "),n("p",[t._v("画面一转，我没有死，原来是一场游戏，我们都复活了，我也可以继续做我想做的事，我兴奋极了。我发现我现在置身于一个村庄，旁边有一个人在向我说垃圾话，我和他骂了起来，他被我骂的扬言要杀了我，还要我的手机号和个人信息想查到我的住处，我没有理他也有恃无恐，反正我可以复活，一切都是一场游戏。我走开了，我知道这又是一场游戏，我也认识这个村庄的管理员，他告诉别人要好好招待我。正当我走到村口时，我碰见了那个骂我的人，此时他手里拿着一把刀，看样子他想在此处杀了我，我也没有怕他，还嘲讽他没这个胆，这个村子的人都很尊敬我，你又敢拿我怎样？他气急败坏的拿刀捅向了我，我知道自己中刀了但也清楚我会以另一种方式活过来。我无力的躺在地上，努力集中意念脱离这场游戏，但我发现我做不到了，我仍然躺在这里，慢慢的我不能再对未来的事情进行任何思考，而是过去的画面不受控制的浮现在眼前，脑海里不断响起一个音乐，我好像看到了这些年各种原因死去的人，对控制感的失去让我发现这既不是游戏也不是梦，我后悔，后悔自己为什么招惹他，后悔自己即将熬过无聊枯燥甚至痛苦的学习生涯，将要面临光彩成功的人生阶段时，却没有机会了。难道在我有生之年经历的都是在压抑自己，逼着自己做本不愿做的事，而这一切都是为了将来能有更好的生活，拖迟满足我做错了吗？我整天幻想事成之后成功的画面，不断劝自己再坚持坚持，多学一些东西，我没有关注我现在的生活也是有意义，也是值得享受的，好像现在我的眼里只有要完成的目标，只有要做成的事，其他生活中的美好我都没有关注，我不甘心，不甘心，不甘心就这样结束了生命，忽然我从梦里醒了过来，摸了摸额头上已经湿了。")])])}),[],!1,null,null,null);e.default=l.exports}}]);